"use client";

import { motion } from "framer-motion";

interface NeonTitleProps {
  text?: string;
  className?: string;
}

export default function NeonTitle({ 
  text = "THE PINK CLUB", 
  className = "" 
}: NeonTitleProps) {
  // Keyframes for flicker animation: off -> on -> off -> dim -> on -> flicker -> steady
  const opacityKeyframes = [0, 1, 0, 0.4, 1, 0.3, 1, 0.5, 1, 0.7, 1, 0.9, 1];
  const timeKeyframes = [0, 0.15, 0.2, 0.35, 0.4, 0.6, 0.65, 0.7, 0.8, 0.85, 0.9, 0.95, 1];

  return (
    <motion.h1
      initial={{ opacity: 0 }}
      animate={{ opacity: opacityKeyframes }}
      transition={{
        duration: 1.8,
        ease: "linear",
        times: timeKeyframes,
      }}
      className={`
        text-6xl sm:text-7xl md:text-8xl lg:text-9xl 
        font-black italic 
        tracking-tighter 
        font-[family-name:var(--font-space-grotesk)] 
        uppercase leading-none 
        text-center
        ${className}
      `}
      style={{
        color: "#ffe6f2",
        textShadow: `
          0 0 5px rgba(255, 0, 127, 0.8),
          0 0 10px rgba(255, 0, 127, 0.8),
          0 0 20px rgba(255, 0, 127, 0.8),
          0 0 40px rgba(255, 0, 127, 0.6),
          0 0 80px rgba(255, 0, 127, 0.4),
          0 0 120px rgba(255, 0, 127, 0.3),
          0 0 200px rgba(255, 0, 127, 0.2),
          0 0 300px rgba(255, 0, 127, 0.1)
        `,
      }}
    >
      {text}
    </motion.h1>
  );
}
